info.narration:
      [
      {วันพรุ่งนี้ของพนักงาน #0 อาจจะมาถึง หรือไม่ก็ได้}
      {ไม่มีใครรู้ว่า -P ที่ถูกกล่าวถึงในวลีคือใคร }
      ]

observe.desc:
      [
      {นาฬิกาเก่า เสียงคลิกของเฟืองสามารถได้ยินได้ในระยะใกล้ มีวลีที่กล่าวว่า “เวลาไหลเหมือนชีวิต ชีวิตไหลเหมือนเวลา” เขียนอยู่ด้านหลัง ไม่ชัดเจนว่าวลีนี้ต้องการสื่อความหมายอะไร}
      ]

max.desc:
        [
        {เวลาเสียไป เวลาหมดไป… สิ่งเหล่านั้นเป็นเพียงอารมณ์ฉุนเฉียวที่ไร้ความหมาย},
        {นาฬิกาเรือนนี้จะไม่เพียงแค่เอาเวลาที่สูญเสียของคุณกลับมา แต่ยังให้เวลาคุณมากขึ้นอีกด้วย},
        {คุณตัดสินใจที่จะ…}
        ]

        [
        {ค่าตอบแทนจะติดตามการตัดสินใจของคุณ},
        {มันถูกออกแบบมาแบบนี้}
        ]

        [
        {ที่จริงแล้ว คุณไม่มีสิทธิ์ที่จะปฏิเสธของขวัญนี้},
        {ไม่ว่าคุณจะต้องการหรือไม่ก็ตาม เราทุกคนรู้ว่าคุณต้องรับมัน}
        ]

max.angela:
        [
        {ความเงียบไม่ได้นำมาซึ่งความสงบอีกต่อไป}
        ]
